import { tool, ToolResult, clearRegistry, getRegisteredTools } from 'protomcp';
import { z } from 'zod';

beforeEach(() => clearRegistry());

test('add tool returns sum', async () => {
  tool({
    name: 'add',
    description: 'Add two numbers',
    args: z.object({ a: z.number(), b: z.number() }),
    handler({ a, b }) {
